const express = require('express');
const redis = require('redis');
const twilio = require('twilio');
const crypto = require('crypto');

const app = express();
app.use(express.json());

const redisClient = redis.createClient();
redisClient.connect();

const twilioClient = twilio(
  process.env.TWILIO_ACCOUNT_SID,
  process.env.TWILIO_AUTH_TOKEN
);

const CODE_EXPIRATION = 600;
const MAX_ATTEMPTS = 10;
const LOCKOUT_DURATION = 3600;

function generateSecureCode() {
  return crypto.randomInt(100000, 999999).toString();
}

app.post('/api/auth/send-code', async (req, res) => {
  try {
    const { userId, phoneNumber } = req.body;

    if (!userId || !phoneNumber) {
      return res.status(400).json({ error: 'Missing required fields' });
    }

    const lockoutKey = `lockout:${userId}`;
    const isLockedOut = await redisClient.get(lockoutKey);

    if (isLockedOut) {
      return res.status(429).json({ error: 'Account temporarily locked. Try again later.' });
    }

    const code = generateSecureCode();
    const codeKey = `mfa:code:${userId}`;
    const attemptsKey = `mfa:attempts:${userId}`;
    const timestampKey = `mfa:timestamp:${userId}`;

    await redisClient.setEx(codeKey, CODE_EXPIRATION, code);
    await redisClient.setEx(attemptsKey, CODE_EXPIRATION, '0');
    await redisClient.setEx(timestampKey, CODE_EXPIRATION, Date.now().toString());

    await twilioClient.messages.create({
      body: `Your verification code is: ${code}. Valid for 10 minutes.`,
      from: process.env.TWILIO_PHONE_NUMBER,
      to: phoneNumber
    });

    res.json({ success: true, message: 'Verification code sent' });
  } catch (error) {
    console.error('Error sending code:', error);
    res.status(500).json({ error: 'Failed to send verification code' });
  }
});

app.post('/api/auth/verify-code', async (req, res) => {
  try {
    const { userId, code } = req.body;

    if (!userId || !code) {
      return res.status(400).json({ error: 'Missing required fields' });
    }

    const lockoutKey = `lockout:${userId}`;
    const isLockedOut = await redisClient.get(lockoutKey);

    if (isLockedOut) {
      return res.status(429).json({ error: 'Account temporarily locked. Try again later.' });
    }

    const codeKey = `mfa:code:${userId}`;
    const attemptsKey = `mfa:attempts:${userId}`;
    const timestampKey = `mfa:timestamp:${userId}`;

    const storedCode = await redisClient.get(codeKey);
    const timestamp = await redisClient.get(timestampKey);

    if (!storedCode || !timestamp) {
      return res.status(400).json({ error: 'No verification code found or code expired' });
    }

    const codeAge = Date.now() - parseInt(timestamp);
    if (codeAge > CODE_EXPIRATION * 1000) {
      await redisClient.del(codeKey);
      await redisClient.del(attemptsKey);
      await redisClient.del(timestampKey);
      return res.status(400).json({ error: 'Verification code expired' });
    }

    const attempts = parseInt(await redisClient.get(attemptsKey) || '0');

    if (attempts >= MAX_ATTEMPTS) {
      await redisClient.setEx(lockoutKey, LOCKOUT_DURATION, '1');
      await redisClient.del(codeKey);
      await redisClient.del(attemptsKey);
      await redisClient.del(timestampKey);
      return res.status(429).json({ error: 'Too many attempts. Account locked for 1 hour.' });
    }

    const inputCodeBuffer = Buffer.from(code.toString());
    const storedCodeBuffer = Buffer.from(storedCode);

    if (inputCodeBuffer.length !== storedCodeBuffer.length) {
      await redisClient.incr(attemptsKey);
      return res.status(401).json({ 
        error: 'Invalid verification code',
        attemptsRemaining: MAX_ATTEMPTS - attempts - 1
      });
    }

    const isValid = crypto.timingSafeEqual(inputCodeBuffer, storedCodeBuffer);

    if (isValid) {
      await redisClient.del(codeKey);
      await redisClient.del(attemptsKey);
      await redisClient.del(timestampKey);

      const sessionToken = crypto.randomBytes(32).toString('hex');
      await redisClient.setEx(`session:${userId}`, 3600, sessionToken);

      res.json({ 
        success: true, 
        message: 'Verification successful',
        sessionToken
      });
    } else {
      await redisClient.incr(attemptsKey);
      res.status(401).json({ 
        error: 'Invalid verification code',
        attemptsRemaining: MAX_ATTEMPTS - attempts - 1
      });
    }
  } catch (error) {
    console.error('Error verifying code:', error);
    res.status(500).json({ error: 'Failed to verify code' });
  }
});

